package com.fasterxml.jackson.databind;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "com.fasterxml.jackson.databind.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package com.fasterxml.jackson.databind.steps;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.annotation.JsonSerialize;
import com.fasterxml.jackson.databind.ser.std.StdSerializer;
import com.fasterxml.jackson.databind.JsonSerializer;
import com.fasterxml.jackson.databind.SerializerProvider;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.junit.Assert;

import java.io.IOException;

public class StepDefs {

    private ObjectMapper mapper;
    private Object testObject;
    private String serializedJson;
    private boolean serializationFailed;

    // Helper classes to simulate the bug scenario
    public static class DummyBean {
        public int a;
        public int b;

        public DummyBean() {}

        public DummyBean(int a, int b) {
            this.a = a;
            this.b = b;
        }
    }

    public static class ConvertingBeanWithUntypedConverter {
        public int x;
        public int y;

        public ConvertingBeanWithUntypedConverter(int x, int y) {
            this.x = x;
            this.y = y;
        }
    }

    @JsonSerialize(using = UntypedConvertingBeanConverter.class)
    public static class ConvertingBeanWithUntypedConverterAnnotated extends ConvertingBeanWithUntypedConverter {
        public ConvertingBeanWithUntypedConverterAnnotated(int x, int y) {
            super(x, y);
        }
    }

    public static class UntypedConvertingBeanConverter extends StdSerializer<ConvertingBeanWithUntypedConverter> {
        public UntypedConvertingBeanConverter() {
            super(ConvertingBeanWithUntypedConverter.class);
        }

        @Override
        public void serialize(ConvertingBeanWithUntypedConverter value, 
                             com.fasterxml.jackson.core.JsonGenerator gen, 
                             SerializerProvider provider) throws IOException {
            // Converter returns a DummyBean instance but declares return type as Object
            DummyBean result = new DummyBean(value.y, value.y * 2); // a=y, b=y*2
            gen.writeObject(result);
        }
    }

    @Given("a POJO \"ConvertingBeanWithUntypedConverter\" is defined with fields \"x\" and \"y\"")
    public void a_pojo_is_defined_with_fields() {
        // This step is satisfied by having the class defined in the code
    }

    @Given("this POJO is annotated to use \"UntypedConvertingBeanConverter\" for serialization")
    public void this_pojo_is_annotated_to_use_for_serialization() {
        // This step is satisfied by the annotation on ConvertingBeanWithUntypedConverterAnnotated
    }

    @Given("the \"UntypedConvertingBeanConverter\" declares a return type of \"java.lang.Object\"")
    public void the_converter_declares_return_type_of_object() {
        // This is part of the converter implementation design
    }

    @Given("the \"UntypedConvertingBeanConverter\" actually returns an instance of \"DummyBean\"")
    public void the_converter_actually_returns_an_instance_of() {
        // This is part of the converter implementation
    }

    @Given("\"DummyBean\" has valid public properties \"a\" and \"b\"")
    public void dummybean_has_valid_public_properties() {
        // This step is satisfied by having the public fields in DummyBean
    }

    @When("I serialize an instance of \"ConvertingBeanWithUntypedConverter\" with x=1 and y=2")
    public void i_serialize_an_instance_with_values() {
        try {
            mapper = new ObjectMapper();
            testObject = new ConvertingBeanWithUntypedConverterAnnotated(1, 2);
            serializedJson = mapper.writeValueAsString(testObject);
            serializationFailed = false;
        } catch (Exception e) {
            serializationFailed = true;
        }
    }

    @Then("the serialization should not fail with \"No serializer found\"")
    public void the_serialization_should_not_fail() {
        Assert.assertFalse("Serialization should not fail", serializationFailed);
    }

    @Then("the resulting JSON should match '{\\\"a\\\":2,\\\"b\\\":4}'")
    public void the_resulting_json_should_match() {
        String expectedJson = "{\"a\":2,\"b\":4}";
        Assert.assertEquals("The JSON should match the expected result", expectedJson, serializedJson);
    }
}
